// Rangos en zona Madrid:
//   Mes anterior: [last_month_ymd, last_month_end_ymd)
//   Semana anterior (lunes-domingo): [last_week_ymd, week_ymd)
const now = new Date();
function madridYMD(d){ return d.toLocaleDateString('en-CA', { timeZone:'Europe/Madrid' }); }
function madridDow(d){
  const wd = new Intl.DateTimeFormat('en-US', { timeZone:'Europe/Madrid', weekday:'short' }).format(d);
  return ['Mon','Tue','Wed','Thu','Fri','Sat','Sun'].indexOf(wd);
}
function ymdToDate(s){ return new Date(s + 'T00:00:00Z'); }
function ymdFromDate(d){ return d.toISOString().substring(0,10); }
function addDays(s,n){ const d = ymdToDate(s); d.setUTCDate(d.getUTCDate()+n); return ymdFromDate(d); }
const todayYMD = madridYMD(now);
const [yy, mm] = todayYMD.split('-');
const monthYMD = `${yy}-${mm}-01`;
const _prev    = ymdToDate(monthYMD); _prev.setUTCMonth(_prev.getUTCMonth() - 1);
const lastMonthYMD    = ymdFromDate(_prev);
const lastMonthEndYMD = monthYMD;
const weekYMD     = addDays(todayYMD, -madridDow(now));
const lastWeekYMD = addDays(weekYMD, -7);
return [{ json: { last_month_ymd: lastMonthYMD, last_month_end_ymd: lastMonthEndYMD, week_ymd: weekYMD, last_week_ymd: lastWeekYMD } }];

// Calcula top 8 orgs del mes anterior y prepara CSV de IDs para resolver nombres.
const dates = $('Calcular fechas').first().json;
const tickets = $input.all().map(i => i.json).filter(Boolean);
const m = new Map();
for (const t of tickets) {
  if (!t || !t.organization_id) continue;
  m.set(t.organization_id, (m.get(t.organization_id) || 0) + 1);
}
const top = [...m.entries()].sort((a,b)=>b[1]-a[1]).slice(0,8);
const ids = top.map(([id])=>id);
return [{ json: { ...dates, _top_raw: top, org_ids_csv: ids.join(',') || '0', _ticket_count: tickets.length } }];

// Resuelve nombres + lee counts de mes/semana anterior + GUARDA EN STATIC DATA.
const dates = $('Calcular fechas').first().json;
const acc   = $('Calcular Top').first().json;
const body  = $input.first().json || {};
const orgs  = Array.isArray(body.organizations) ? body.organizations : [];
const orgMap = new Map();
for (const o of orgs) { if (o && o.id) orgMap.set(o.id, o.name); }
const top_orgs_last_month = (acc._top_raw || []).map(([id, count]) => ({
  name: orgMap.get(id) || `Organización ${id}`,
  count
}));
// search.json con per_page=1 devuelve el campo 'count' total sin paginar.
const monthCountBody = $('ZD Mes Ant Count').first().json || {};
const weekCountBody  = $('ZD Sem Ant Count').first().json || {};
const monthIaBody    = $('ZD Mes Ant IA Count').first().json || {};
const monthManBody   = $('ZD Mes Ant Manual Count').first().json || {};
const tickets_last_month = typeof monthCountBody.count === 'number' ? monthCountBody.count : null;
const tickets_last_week  = typeof weekCountBody.count  === 'number' ? weekCountBody.count  : null;
const tickets_last_month_ia     = typeof monthIaBody.count  === 'number' ? monthIaBody.count  : null;
const tickets_last_month_manual = typeof monthManBody.count === 'number' ? monthManBody.count : null;
const payload = {
  generated_at:       new Date().toISOString(),
  last_month_ymd:     dates.last_month_ymd,
  last_month_end_ymd: dates.last_month_end_ymd,
  last_week_ymd:      dates.last_week_ymd,
  week_ymd:           dates.week_ymd,
  ticket_count_paginated: acc._ticket_count,
  tickets_last_month,
  tickets_last_month_ia,
  tickets_last_month_manual,
  tickets_last_week,
  top_orgs_last_month
};
const staticData = $getWorkflowStaticData('global');
staticData.cached_payload = payload;
staticData.cached_at      = payload.generated_at;
return [{ json: { saved: true, ...payload } }];

// Lee el último resultado cacheado por el Schedule Trigger.
// Si la caché está vacía (primer arranque), devuelve estructura vacía y _stale=true.
const staticData = $getWorkflowStaticData('global');
const cached = staticData.cached_payload || null;
if (!cached) {
  return [{ json: {
    generated_at: null,
    cached_at: null,
    _stale: true,
    _hint: 'Cache vacía. Lanza manualmente el Schedule Trigger una vez.',
    top_orgs_last_month: [],
    tickets_last_month: null,
    tickets_last_month_ia: null,
    tickets_last_month_manual: null,
    tickets_last_week:  null
  } }];
}
return [{ json: { ...cached, cached_at: staticData.cached_at, _stale: false } }];
